import { SceneMergerApplication } from "../apps/scene-merger/SceneMergerApplication";
import { I18N_PREFIX, MODULE_ID } from "../constants";
import { requireGame } from "../runtime/runtime-utils";

export function registerSettings(): void {
  const settings = requireGame().settings;
  settings.register(MODULE_ID, "cleanupPartialDestination", {
    config: true,
    default: true,
    hint: `${I18N_PREFIX}.Settings.CleanupPartial.Hint`,
    name: `${I18N_PREFIX}.Settings.CleanupPartial.Name`,
    scope: "world",
    type: Boolean,
  });
  settings.register(MODULE_ID, "debugLogging", {
    config: true,
    default: false,
    hint: `${I18N_PREFIX}.Settings.DebugLogging.Hint`,
    name: `${I18N_PREFIX}.Settings.DebugLogging.Name`,
    scope: "client",
    type: Boolean,
  });
  settings.registerMenu(MODULE_ID, "sceneMerger", {
    icon: "fa-solid fa-object-group",
    label: `${I18N_PREFIX}.Settings.Open.Label`,
    name: `${I18N_PREFIX}.Settings.Open.Name`,
    restricted: true,
    type: SceneMergerApplication,
  });
}
