import type {
  CoreDocumentType,
  ReferenceRewriteContext,
  ReferenceRewriteResult,
} from "../../../types/scene-merger";

import { createSourceDocumentKey } from "./keys";

const CORE_DOCUMENT_TYPES = new Set<CoreDocumentType>([
  "Level",
  "Tile",
  "Wall",
  "AmbientLight",
  "AmbientSound",
  "Drawing",
  "Note",
  "Region",
  "RegionBehavior",
  "Token",
]);

function isCoreDocumentType(value: string): value is CoreDocumentType {
  return CORE_DOCUMENT_TYPES.has(value as CoreDocumentType);
}

export function mappedDocumentId(
  context: ReferenceRewriteContext,
  documentType: CoreDocumentType,
  documentId: string,
  parentIds: readonly string[] = [],
  sourceSceneId = context.sourceSceneId,
): string | undefined {
  return context.idMap.get(
    createSourceDocumentKey(sourceSceneId, documentType, documentId, parentIds),
  );
}

export function rewriteSceneUuid(
  value: string,
  context: ReferenceRewriteContext,
): ReferenceRewriteResult<string> {
  const parts = value.split(".");
  const targetSceneId = parts[1];

  if (parts[0] !== "Scene" || !targetSceneId || !context.sourceSceneIds.includes(targetSceneId)) {
    return { rewritten: 0, unresolved: [], value };
  }

  if (parts.length === 2) {
    return { rewritten: 1, unresolved: [], value: `Scene.${context.destinationSceneId}` };
  }

  const rewrittenParts = ["Scene", context.destinationSceneId];
  const parentSourceIds: string[] = [];
  let rewritten = 1;

  for (let index = 2; index < parts.length; index += 2) {
    const documentType = parts[index];
    const documentId = parts[index + 1];

    if (!documentType || !documentId) {
      return { rewritten: 0, unresolved: [value], value };
    }

    if (!isCoreDocumentType(documentType)) {
      return { rewritten: 0, unresolved: [value], value };
    }

    const mappedId = mappedDocumentId(
      context,
      documentType,
      documentId,
      parentSourceIds,
      targetSceneId,
    );

    if (!mappedId) {
      return { rewritten: 0, unresolved: [value], value };
    }

    rewrittenParts.push(documentType, mappedId);
    parentSourceIds.push(documentId);
    rewritten += 1;
  }

  return { rewritten, unresolved: [], value: rewrittenParts.join(".") };
}
