import type { ContentSelection, SceneSnapshot, ValidationIssue } from "../../types/scene-merger";

import { asRecord } from "./runtime-utils";

type AssetProbeResult = "available" | "missing" | "unverified";

const PROBE_LIMIT = 64;
const PROBE_TIMEOUT_MS = 4_000;
const probeCache = new Map<string, Promise<AssetProbeResult>>();

export async function validateSourceAssets(
  scenes: readonly SceneSnapshot[],
  selection: ContentSelection,
): Promise<readonly ValidationIssue[]> {
  const sceneIssues = await Promise.all(
    scenes.map(async (scene): Promise<readonly ValidationIssue[]> => {
      const issues: ValidationIssue[] = [];
      const paths = collectAssetPaths(scene, selection);
      const probed = paths.slice(0, PROBE_LIMIT);
      const results = await Promise.all(probed.map(probeAsset));
      const missing = results.filter((result) => result === "missing").length;
      const unverified =
        results.filter((result) => result === "unverified").length +
        Math.max(0, paths.length - probed.length);

      if (missing > 0) issues.push(assetIssue("assets.unavailable", scene.id, missing));
      if (unverified > 0) issues.push(assetIssue("assets.unverified", scene.id, unverified));
      return issues;
    }),
  );

  return sceneIssues.flat();
}

function collectAssetPaths(scene: SceneSnapshot, selection: ContentSelection): readonly string[] {
  const paths = new Set<string>();

  if (selection.backgrounds) {
    for (const level of scene.documents.Level ?? []) {
      addTexturePath(paths, asRecord(level["background"]));
      addTexturePath(paths, asRecord(level["foreground"]));
    }
  }

  if (selection.tiles) {
    for (const tile of scene.documents.Tile ?? []) {
      addTexturePath(paths, asRecord(tile["texture"]));
    }
  }

  return [...paths];
}

function addTexturePath(paths: Set<string>, texture: Record<string, unknown> | undefined): void {
  const source = texture?.["src"];
  if (typeof source === "string" && source.trim().length > 0) paths.add(source);
}

function probeAsset(source: string): Promise<AssetProbeResult> {
  const existing = probeCache.get(source);
  if (existing) return existing;

  const pending = performProbe(source);
  probeCache.set(source, pending);
  return pending;
}

async function performProbe(source: string): Promise<AssetProbeResult> {
  if (/^(?:data|blob):/i.test(source)) return "available";

  const controller = new AbortController();
  const timeout = globalThis.setTimeout(() => controller.abort(), PROBE_TIMEOUT_MS);
  try {
    const response = await fetch(source, {
      credentials: "same-origin",
      method: "HEAD",
      signal: controller.signal,
    });
    if (response.ok) return "available";
    if (response.status === 404 || response.status === 410) return "missing";
    return "unverified";
  } catch {
    return "unverified";
  } finally {
    globalThis.clearTimeout(timeout);
  }
}

function assetIssue(
  code: "assets.unavailable" | "assets.unverified",
  sceneId: string,
  count: number,
): ValidationIssue {
  return {
    code,
    details: { count },
    overridable: true,
    sceneIds: [sceneId],
    severity: "warning",
  };
}
