import type {
  Bounds,
  PlacementOverlap,
  Rectangle,
  ScenePlacement,
} from "../../../types/scene-merger";

import { createBounds } from "./bounds";

export function intersectionBounds(first: Rectangle, second: Rectangle): Bounds | null {
  const minX = Math.max(first.x, second.x);
  const minY = Math.max(first.y, second.y);
  const maxX = Math.min(first.x + first.width, second.x + second.width);
  const maxY = Math.min(first.y + first.height, second.y + second.height);

  return maxX > minX && maxY > minY ? createBounds(minX, minY, maxX, maxY) : null;
}

export function rectanglesOverlap(first: Rectangle, second: Rectangle): boolean {
  return intersectionBounds(first, second) !== null;
}

export function findPlacementOverlaps(
  placements: readonly ScenePlacement[],
): readonly PlacementOverlap[] {
  const overlaps: PlacementOverlap[] = [];

  for (let firstIndex = 0; firstIndex < placements.length; firstIndex += 1) {
    const first = placements[firstIndex];

    if (!first) {
      continue;
    }

    for (let secondIndex = firstIndex + 1; secondIndex < placements.length; secondIndex += 1) {
      const second = placements[secondIndex];

      if (!second) {
        continue;
      }

      const intersection = intersectionBounds(first, second);

      if (intersection) {
        overlaps.push({
          firstSceneId: first.sceneId,
          intersection,
          secondSceneId: second.sceneId,
        });
      }
    }
  }

  return overlaps;
}
