import type { ModuleApi } from "../../types/module/api";
import { openSceneMergerApplication } from "../apps/scene-merger/SceneMergerApplication";
import {
  registerDocumentTransformer,
  registerExtension,
  registerReferenceRewriter,
  registerValidator,
} from "../extensions/extension-registry";
import { sceneMergerService } from "../runtime/scene-merger-service";

export function createModuleApi(): ModuleApi {
  return {
    cancelActiveMerge: sceneMergerService.cancelActiveMerge,
    listSceneFolders: sceneMergerService.listSceneFolders,
    listScenes: sceneMergerService.listScenes,
    merge: sceneMergerService.merge,
    open: openSceneMergerApplication,
    openScene: sceneMergerService.openScene,
    registerDocumentTransformer,
    registerExtension,
    registerReferenceRewriter,
    registerValidator,
    validate: sceneMergerService.validate,
  };
}
