import type {
  Bounds,
  ContentSelection,
  CoreDocumentType,
  MergeEstimate,
  PerformanceThresholds,
  SceneDocumentCounts,
  SceneSummary,
  ValidationIssue,
} from "../../../types/scene-merger";

import { CONTENT_DOCUMENT_TYPES } from "../content";

export const DEFAULT_PERFORMANCE_THRESHOLDS: PerformanceThresholds = {
  animatedAssets: 12,
  area: 150_000_000,
  backgrounds: 20,
  dimension: 16_384,
  lights: 500,
  regions: 500,
  sounds: 500,
  texturePixels: 250_000_000,
  tiles: 1_000,
  tokens: 1_000,
  walls: 5_000,
};

function count(documents: SceneDocumentCounts, type: keyof SceneDocumentCounts): number {
  return documents[type] ?? 0;
}

export function estimateMergeCost(
  scenes: readonly SceneSummary[],
  bounds: Bounds,
  selection?: ContentSelection,
): MergeEstimate {
  const documents: Record<string, number> = {};
  const enabledTypes = selectedDocumentTypes(selection);

  for (const scene of scenes) {
    for (const [type, amount] of Object.entries(scene.metrics.documents)) {
      if (enabledTypes && !enabledTypes.has(type as CoreDocumentType)) continue;
      documents[type] = (documents[type] ?? 0) + (amount ?? 0);
    }
  }

  const includeTextures = !selection || selection.backgrounds || selection.tiles;

  return {
    animatedAssets: includeTextures
      ? scenes.reduce((total, scene) => total + scene.metrics.animatedAssets, 0)
      : 0,
    backgrounds:
      !selection || selection.backgrounds
        ? scenes.reduce((total, scene) => total + scene.metrics.backgroundImages, 0)
        : 0,
    bounds,
    documents,
    sourceCount: scenes.length,
    texturePixels: includeTextures
      ? scenes.reduce((total, scene) => total + scene.metrics.texturePixels, 0)
      : 0,
  };
}

function selectedDocumentTypes(selection?: ContentSelection): ReadonlySet<CoreDocumentType> | null {
  if (!selection) return null;
  return new Set(
    Object.entries(CONTENT_DOCUMENT_TYPES).flatMap(([category, type]) =>
      type && selection[category as keyof ContentSelection] ? [type] : [],
    ),
  );
}

function warning(code: ValidationIssue["code"], value: number, threshold: number): ValidationIssue {
  return {
    code,
    details: { threshold, value },
    overridable: true,
    sceneIds: [],
    severity: "warning",
  };
}

export function collectPerformanceWarnings(
  estimate: MergeEstimate,
  thresholds: PerformanceThresholds = DEFAULT_PERFORMANCE_THRESHOLDS,
): readonly ValidationIssue[] {
  const issues: ValidationIssue[] = [];
  const dimension = Math.max(estimate.bounds.width, estimate.bounds.height);
  const area = estimate.bounds.width * estimate.bounds.height;
  const checks: readonly [ValidationIssue["code"], number, number][] = [
    ["performance.dimension", dimension, thresholds.dimension],
    ["performance.area", area, thresholds.area],
    ["performance.textures", estimate.texturePixels, thresholds.texturePixels],
    ["performance.backgrounds", estimate.backgrounds, thresholds.backgrounds],
    [
      "performance.tiles",
      count(estimate.documents, "Tile") + estimate.backgrounds,
      thresholds.tiles,
    ],
    ["performance.animatedAssets", estimate.animatedAssets, thresholds.animatedAssets],
    ["performance.walls", count(estimate.documents, "Wall"), thresholds.walls],
    ["performance.lights", count(estimate.documents, "AmbientLight"), thresholds.lights],
    ["performance.sounds", count(estimate.documents, "AmbientSound"), thresholds.sounds],
    ["performance.tokens", count(estimate.documents, "Token"), thresholds.tokens],
    ["performance.regions", count(estimate.documents, "Region"), thresholds.regions],
  ];

  for (const [code, value, threshold] of checks) {
    if (value > threshold) {
      issues.push(warning(code, value, threshold));
    }
  }

  return issues;
}
