import type { Bounds, Point, ViewportSize, WorkspaceView } from "../../../types/scene-merger";

export const MIN_WORKSPACE_ZOOM = 0.02;
export const MAX_WORKSPACE_ZOOM = 8;

export function clampZoom(
  zoom: number,
  minimum = MIN_WORKSPACE_ZOOM,
  maximum = MAX_WORKSPACE_ZOOM,
): number {
  return Math.min(maximum, Math.max(minimum, zoom));
}

export function calculateZoomToFit(
  bounds: Bounds,
  viewport: ViewportSize,
  padding = 32,
): WorkspaceView {
  const availableWidth = Math.max(1, viewport.width - padding * 2);
  const availableHeight = Math.max(1, viewport.height - padding * 2);
  const widthZoom = bounds.width > 0 ? availableWidth / bounds.width : 1;
  const heightZoom = bounds.height > 0 ? availableHeight / bounds.height : 1;
  const zoom = clampZoom(Math.min(widthZoom, heightZoom, 1));

  return {
    panX: (viewport.width - bounds.width * zoom) / 2 - bounds.minX * zoom,
    panY: (viewport.height - bounds.height * zoom) / 2 - bounds.minY * zoom,
    zoom,
  };
}

export function zoomAroundPoint(
  view: WorkspaceView,
  nextZoom: number,
  screenPoint: Point,
): WorkspaceView {
  const zoom = clampZoom(nextZoom);
  const worldX = (screenPoint.x - view.panX) / view.zoom;
  const worldY = (screenPoint.y - view.panY) / view.zoom;

  return {
    panX: screenPoint.x - worldX * zoom,
    panY: screenPoint.y - worldY * zoom,
    zoom,
  };
}
