import { sourceDocumentKey } from "../../functions/scene-merger";
import type { FoundryData, FoundryDocument } from "../../types/foundry";
import type { SourceDocumentIdentity, SourceDocumentKey } from "../../types/scene-merger";
import { MODULE_ID } from "../constants";
import { asRecord, asRecords, cloneRecord, documentId, serializeDocument } from "./runtime-utils";

const PROVENANCE_KEY = "_temporaryProvenance";

export function attachProvenance(
  source: FoundryData,
  identity: SourceDocumentIdentity,
): FoundryData {
  const data = cloneRecord(source);
  const flags = cloneRecord(asRecord(data["flags"]) ?? {});
  const moduleFlags = cloneRecord(asRecord(flags[MODULE_ID]) ?? {});
  const hadPrevious = Object.hasOwn(moduleFlags, PROVENANCE_KEY);
  const previousValue = moduleFlags[PROVENANCE_KEY];
  moduleFlags[PROVENANCE_KEY] = {
    documentId: identity.documentId,
    documentType: identity.documentType,
    parentIds: [...(identity.parentIds ?? [])],
    sceneId: identity.sceneId,
    sourceKey: sourceDocumentKey(identity),
    hadPrevious,
    previousValue,
  };
  flags[MODULE_ID] = moduleFlags;
  data["flags"] = flags;
  return data;
}

export function removeTemporaryProvenance(source: FoundryData): FoundryData {
  const data = cloneRecord(source);
  const flags = asRecord(data["flags"]);
  const moduleFlags = asRecord(flags?.[MODULE_ID]);
  const provenance = asRecord(moduleFlags?.[PROVENANCE_KEY]);
  if (flags && moduleFlags && provenance) {
    if (provenance["hadPrevious"] === true) {
      moduleFlags[PROVENANCE_KEY] = cloneRecordValue(provenance["previousValue"]);
    } else {
      delete moduleFlags[PROVENANCE_KEY];
    }
    if (Object.keys(moduleFlags).length === 0) delete flags[MODULE_ID];
    data["flags"] = flags;
  }
  delete data["_stats"];
  if (Array.isArray(data["behaviors"])) {
    data["behaviors"] = asRecords(data["behaviors"]).map(removeTemporaryProvenance);
  }
  return data;
}

function cloneRecordValue(value: unknown): unknown {
  return value && typeof value === "object" ? cloneRecord(value as FoundryData) : value;
}

export function readProvenance(data: FoundryData): SourceDocumentIdentity | undefined {
  const flags = asRecord(data["flags"]);
  const moduleFlags = asRecord(flags?.[MODULE_ID]);
  const provenance = asRecord(moduleFlags?.[PROVENANCE_KEY]);
  if (!provenance) return undefined;
  const documentId = provenance?.["documentId"];
  const documentType = provenance?.["documentType"];
  const sceneId = provenance?.["sceneId"];
  if (
    typeof documentId !== "string" ||
    typeof documentType !== "string" ||
    typeof sceneId !== "string"
  ) {
    return undefined;
  }
  const parentIds = Array.isArray(provenance["parentIds"])
    ? provenance["parentIds"].filter((value): value is string => typeof value === "string")
    : [];
  return {
    documentId,
    documentType: documentType as SourceDocumentIdentity["documentType"],
    parentIds,
    sceneId,
  };
}

export function recordCreatedIds(
  created: readonly FoundryDocument[],
  idMap: Map<SourceDocumentKey, string>,
): readonly string[] {
  const unresolved: string[] = [];
  for (const document of created) {
    const data = serializeDocument(document);
    recordDataIdentity(data, idMap, unresolved);
    for (const behavior of asRecords(data["behaviors"])) {
      recordDataIdentity(behavior, idMap, unresolved);
    }
  }
  return unresolved;
}

function recordDataIdentity(
  data: FoundryData,
  idMap: Map<SourceDocumentKey, string>,
  unresolved: string[],
): void {
  const identity = readProvenance(data);
  const createdId = documentId(data);
  if (!identity || !createdId) {
    unresolved.push("A created document could not be associated with its source provenance.");
    return;
  }
  idMap.set(sourceDocumentKey(identity), createdId);
}
