import type {
  MergeOptions,
  PerformanceThresholds,
  ScenePlacement,
  SceneSummary,
  ValidationIssue,
  ValidationReport,
} from "../../../types/scene-merger";

import { calculateArrangementBounds } from "../layout/bounds";
import { validateCompatibility } from "./compatibility";
import {
  collectPerformanceWarnings,
  DEFAULT_PERFORMANCE_THRESHOLDS,
  estimateMergeCost,
} from "./performance";

export function createValidationReport(issues: readonly ValidationIssue[]): ValidationReport {
  const blocking = issues.filter((issue) => issue.severity === "error");
  const warnings = issues.filter((issue) => issue.severity !== "error");

  return { blocking, canMerge: blocking.length === 0, warnings };
}

export function validateMergeInput(
  scenes: readonly SceneSummary[],
  placements: readonly ScenePlacement[],
  options: MergeOptions,
  thresholds: PerformanceThresholds = DEFAULT_PERFORMANCE_THRESHOLDS,
): ValidationReport {
  const bounds = calculateArrangementBounds(placements);
  const estimate = estimateMergeCost(scenes, bounds, options.content);
  const issues = [
    ...validateCompatibility(scenes, placements, options),
    ...collectPerformanceWarnings(estimate, thresholds),
  ];

  return createValidationReport(issues);
}
