import type { Bounds, Rectangle } from "../../../types/scene-merger";

export function createBounds(minX: number, minY: number, maxX: number, maxY: number): Bounds {
  return {
    height: Math.max(0, maxY - minY),
    maxX,
    maxY,
    minX,
    minY,
    width: Math.max(0, maxX - minX),
  };
}

export function rectangleBounds(rectangle: Rectangle): Bounds {
  return createBounds(
    rectangle.x,
    rectangle.y,
    rectangle.x + rectangle.width,
    rectangle.y + rectangle.height,
  );
}

export function calculateArrangementBounds(rectangles: readonly Rectangle[]): Bounds {
  if (rectangles.length === 0) {
    return createBounds(0, 0, 0, 0);
  }

  return createBounds(
    Math.min(...rectangles.map((rectangle) => rectangle.x)),
    Math.min(...rectangles.map((rectangle) => rectangle.y)),
    Math.max(...rectangles.map((rectangle) => rectangle.x + rectangle.width)),
    Math.max(...rectangles.map((rectangle) => rectangle.y + rectangle.height)),
  );
}
