import type { FoundryData, FoundryDocument, FoundryGame, FoundryScene } from "../../types/foundry";
import type { SerializedRecord } from "../../types/scene-merger";

export function requireGame(): FoundryGame {
  if (!game) {
    throw new Error("Foundry game data is not available yet.");
  }
  return game;
}

export function requireScene(sceneId: string): FoundryScene {
  const scene = requireGame().scenes.get(sceneId);
  if (!scene) {
    throw new Error(`Source Scene ${sceneId} is unavailable.`);
  }
  return scene;
}

export function cloneRecord(value: FoundryData | SerializedRecord): FoundryData {
  return cloneValue(value) as FoundryData;
}

export function serializeDocument(document: FoundryDocument): FoundryData {
  return cloneRecord(document.toObject(true));
}

export function cloneValue(value: unknown): unknown {
  if (Array.isArray(value)) {
    return value.map(cloneValue);
  }
  if (value instanceof Set) {
    return [...value].map(cloneValue);
  }
  if (value && typeof value === "object") {
    const result: Record<string, unknown> = {};
    for (const [key, child] of Object.entries(value)) {
      result[key] = cloneValue(child);
    }
    return result;
  }
  return value;
}

export function asRecord(value: unknown): FoundryData | undefined {
  if (!value || typeof value !== "object" || Array.isArray(value)) {
    return undefined;
  }
  return value as FoundryData;
}

export function asRecords(value: unknown): FoundryData[] {
  return Array.isArray(value)
    ? value.map(asRecord).filter((record): record is FoundryData => Boolean(record))
    : [];
}

export function numeric(value: unknown, fallback = 0): number {
  return typeof value === "number" && Number.isFinite(value) ? value : fallback;
}

export function text(value: unknown, fallback = ""): string {
  return typeof value === "string" ? value : fallback;
}

export function documentId(data: FoundryData): string | undefined {
  const id = data["_id"];
  return typeof id === "string" && id.length > 0 ? id : undefined;
}

export function errorMessage(error: unknown): string {
  return error instanceof Error ? error.message : String(error);
}

export function isAnimatedAsset(path: unknown): boolean {
  return typeof path === "string" && /\.(?:m4v|mp4|ogg|ogv|webm)(?:[?#].*)?$/i.test(path);
}

export async function yieldToBrowser(): Promise<void> {
  await new Promise<void>((resolve) => {
    setTimeout(resolve, 0);
  });
}

export function formatIssueCode(code: string): string {
  return code
    .replace(/([a-z])([A-Z])/g, "$1 $2")
    .replaceAll(".", ": ")
    .replace(/^./, (character) => character.toUpperCase());
}
