import { computed, reactive, ref, shallowRef } from "vue";
import { defineStore } from "pinia";

import { createDefaultMergeOptions, snapPlacement } from "../../functions/scene-merger";
import {
  CORE_CONTENT_CAPABILITIES,
  type ContentCategory,
  type MergeProgress,
  type MergeStage,
  type MergeSummary,
  type ScenePlacement,
  type SceneFolderSummary,
  type SceneSummary,
  type ValidationReport,
} from "../../types/scene-merger";
import type { CancellableSceneMergerServices } from "./contracts";
import { createWorkflowDerivations } from "./derivations";
import { resolveMergeFailureStage } from "./errors";
import { createWorkspaceState } from "./workspace";

type WorkflowStatus = "loading" | "ready" | "merging" | "success" | "failure";

export const useSceneMergerStore = defineStore("scene-merger", () => {
  const defaults = createDefaultMergeOptions("Merged Scene");
  const services = shallowRef<CancellableSceneMergerServices | null>(null);
  const availableScenes = ref<readonly SceneSummary[]>([]);
  const sceneFolders = ref<readonly SceneFolderSummary[]>([]);
  const placements = ref<readonly ScenePlacement[]>([]);
  const content = reactive<Record<ContentCategory, boolean>>({ ...defaults.content });
  const destination = reactive({ ...defaults.destination });
  const status = ref<WorkflowStatus>("loading");
  const validation = ref<ValidationReport | null>(null);
  const validating = ref(false);
  const warningsAcknowledged = ref(false);
  const progress = ref<MergeProgress | null>(null);
  const summary = ref<MergeSummary | null>(null);
  const failureMessage = ref("");
  const failureStage = ref<MergeStage | "beforeDestination">("beforeDestination");
  const cancelRequested = ref(false);
  let validationRevision = 0;
  const setupEditable = computed(() => status.value === "ready");

  const {
    arrangementBounds,
    currentRequest,
    folderChoices,
    overlaps,
    selectedSceneIds,
    selectedScenes,
  } = createWorkflowDerivations({
    availableScenes,
    content,
    destination,
    placements,
    sceneFolders,
    validation,
    warningsAcknowledged,
  });
  const { fitView, locateScene, resetView, setSnap, setView, snap, view, zoomAt } =
    createWorkspaceState(placements, arrangementBounds, () => setupEditable.value);
  const canMerge = computed(
    () =>
      setupEditable.value &&
      !validating.value &&
      Boolean(validation.value?.canMerge) &&
      (validation.value?.warnings.length === 0 || warningsAcknowledged.value),
  );
  const canCancel = computed(
    () =>
      status.value === "merging" &&
      !cancelRequested.value &&
      Boolean(services.value?.cancelActiveMerge) &&
      (!progress.value ||
        progress.value.stage === "validating" ||
        progress.value.stage === "calculatingBounds"),
  );

  async function initialize(
    runtime: CancellableSceneMergerServices,
    defaultName: string,
  ): Promise<void> {
    services.value = runtime;
    destination.name = defaultName;
    status.value = "loading";
    try {
      [availableScenes.value, sceneFolders.value] = await Promise.all([
        runtime.listScenes(),
        runtime.listSceneFolders(),
      ]);
      status.value = "ready";
      await validateNow();
    } catch (error) {
      fail(error, "beforeDestination");
    }
  }

  function addScene(sceneId: string): void {
    if (!setupEditable.value || selectedSceneIds.value.includes(sceneId)) return;
    const scene = availableScenes.value.find(({ id }) => id === sceneId);
    if (!scene) return;
    const bounds = arrangementBounds.value;
    const x = placements.value.length === 0 ? 0 : bounds.maxX + Math.max(50, scene.grid.size);
    placements.value = [
      ...placements.value,
      {
        height: scene.dimensions.sceneHeight,
        order: placements.value.length,
        sceneId,
        width: scene.dimensions.sceneWidth,
        x,
        y: placements.value.length === 0 ? 0 : bounds.minY,
      },
    ];
    if (placements.value.length === 1) snap.gridSize = scene.grid.size;
    invalidate();
    void validateNow();
  }

  function removeScene(sceneId: string): void {
    if (!setupEditable.value) return;
    placements.value = placements.value
      .filter((item) => item.sceneId !== sceneId)
      .map((item, order) => ({ ...item, order }));
    invalidate();
    void validateNow();
  }

  function clearScenes(): void {
    if (!setupEditable.value) return;
    placements.value = [];
    invalidate();
    void validateNow();
  }

  function reorderScene(sceneId: string, direction: -1 | 1): void {
    if (!setupEditable.value) return;
    const items = [...placements.value];
    const index = items.findIndex((item) => item.sceneId === sceneId);
    const target = index + direction;
    if (index < 0 || target < 0 || target >= items.length) return;
    [items[index], items[target]] = [items[target]!, items[index]!];
    placements.value = items.map((item, order) => ({ ...item, order }));
    invalidate();
    void validateNow();
  }

  function moveScene(sceneId: string, x: number, y: number, applySnap = true): void {
    if (!setupEditable.value) return;
    const current = placements.value.find((item) => item.sceneId === sceneId);
    if (!current) return;
    const candidate = { ...current, x: Math.round(x), y: Math.round(y) };
    const next = applySnap
      ? snapPlacement(
          candidate,
          snap,
          placements.value.filter((item) => item.sceneId !== sceneId),
          view.value.zoom,
        )
      : candidate;
    placements.value = placements.value.map((item) => (item.sceneId === sceneId ? next : item));
    invalidate();
  }

  function setContent(category: ContentCategory, enabled: boolean): void {
    if (!setupEditable.value || CORE_CONTENT_CAPABILITIES[category] === "unavailable") return;
    content[category] = enabled;
    invalidate();
    void validateNow();
  }

  function setDestination<K extends keyof typeof destination>(
    key: K,
    value: (typeof destination)[K],
  ): void {
    if (!setupEditable.value) return;
    destination[key] = value;
    invalidate();
    void validateNow();
  }

  async function validateNow(): Promise<void> {
    if (!services.value || !setupEditable.value) return;
    const revision = ++validationRevision;
    validating.value = true;
    try {
      const report = await services.value.validate(currentRequest.value);
      if (revision === validationRevision) validation.value = report;
    } catch (error) {
      if (revision === validationRevision) fail(error, "beforeDestination");
    } finally {
      if (revision === validationRevision) validating.value = false;
    }
  }

  async function merge(): Promise<void> {
    if (!services.value || !setupEditable.value) return;
    await validateNow();
    if (!canMerge.value) return;
    status.value = "merging";
    progress.value = null;
    cancelRequested.value = false;
    try {
      summary.value = await services.value.merge(currentRequest.value, (next) => {
        progress.value = next;
      });
      status.value = "success";
    } catch (error) {
      const fallback = (progress.value as MergeProgress | null)?.stage ?? "beforeDestination";
      fail(error, resolveMergeFailureStage(error, fallback));
    }
  }

  async function cancelMerge(): Promise<void> {
    if (!canCancel.value) return;
    cancelRequested.value = true;
    await services.value?.cancelActiveMerge?.();
  }

  async function openDestination(): Promise<void> {
    if (summary.value && services.value)
      await services.value.openScene(summary.value.destinationSceneId);
  }

  function setWarningsAcknowledged(acknowledged: boolean): void {
    if (!setupEditable.value) return;
    warningsAcknowledged.value = acknowledged;
  }

  function returnToEditing(): void {
    status.value = "ready";
    progress.value = null;
    cancelRequested.value = false;
    failureMessage.value = "";
    void validateNow();
  }

  function invalidate(): void {
    warningsAcknowledged.value = false;
    summary.value = null;
  }

  function fail(error: unknown, stage: MergeStage | "beforeDestination"): void {
    failureMessage.value = error instanceof Error ? error.message : String(error);
    failureStage.value = stage;
    status.value = "failure";
  }

  return {
    arrangementBounds,
    availableScenes,
    canCancel,
    canMerge,
    cancelMerge,
    cancelRequested,
    clearScenes,
    content,
    destination,
    failureMessage,
    failureStage,
    fitView,
    folderChoices,
    initialize,
    locateScene,
    merge,
    moveScene,
    openDestination,
    overlaps,
    placements,
    progress,
    removeScene,
    reorderScene,
    resetView,
    returnToEditing,
    selectedSceneIds,
    selectedScenes,
    setContent,
    setDestination,
    setSnap,
    setView,
    setWarningsAcknowledged,
    setupEditable,
    snap,
    status,
    summary,
    validateNow,
    validating,
    validation,
    view,
    warningsAcknowledged,
    zoomAt,
    addScene,
  };
});
