import {
  calculateDocumentDelta,
  enabledDocumentTypes,
  transformLevelMembership,
  translateDrawingDocument,
  translatePointDocument,
  translateRectangleDocument,
  translateRegionDocument,
  translateTokenDocument,
  translateWallDocument,
} from "../../functions/scene-merger";
import type { FoundryData, FoundrySceneDimensions } from "../../types/foundry";
import type {
  CoreDocumentType,
  DocumentTransformContext,
  LevelMembershipData,
  MergeRequest,
  Point,
  RegionDocumentData,
  SceneGridSettings,
  ScenePlacement,
  SceneSnapshot,
  SourceDocumentIdentity,
} from "../../types/scene-merger";
import { registeredExtensions } from "../extensions/extension-registry";
import { attachProvenance } from "./provenance";
import { asRecords, cloneRecord, documentId, numeric } from "./runtime-utils";

export interface PreparedDocument {
  readonly creationData: FoundryData;
  readonly data: FoundryData;
  readonly identity: SourceDocumentIdentity;
  readonly type: CoreDocumentType;
}

export interface PreparedDocuments {
  readonly batches: ReadonlyMap<CoreDocumentType, readonly PreparedDocument[]>;
  readonly skipped: Readonly<Partial<Record<CoreDocumentType, number>>>;
}

export function prepareDocuments(
  scenes: readonly SceneSnapshot[],
  placements: readonly ScenePlacement[],
  destination: FoundrySceneDimensions & { readonly id: string; readonly levelId: string },
  request: MergeRequest,
  onTransform?: (data: FoundryData, context: DocumentTransformContext) => void,
): PreparedDocuments {
  const enabled = new Set(enabledDocumentTypes(request.options.content));
  const placementById = new Map(placements.map((placement) => [placement.sceneId, placement]));
  const stackById = new Map(
    [...placements]
      .sort((left, right) => left.order - right.order)
      .map((placement, index) => [placement.sceneId, index]),
  );
  const stackStride = Math.max(1, ...scenes.map((scene) => scene.documents.Tile?.length ?? 0)) + 1;
  const batches = new Map<CoreDocumentType, PreparedDocument[]>();
  const skipped: Partial<Record<CoreDocumentType, number>> = {};

  for (const scene of scenes) {
    const placement = placementById.get(scene.id);
    if (!placement) continue;
    const delta = calculateDocumentDelta(scene.dimensions, destination, placement);
    const sourceLevelId = scene.levels[0]?.id;
    const stack = stackById.get(scene.id) ?? 0;
    if (!sourceLevelId) continue;
    const levelMap = new Map([[sourceLevelId, destination.levelId]]);

    for (const type of enabled) {
      const sources = [...(scene.documents[type] ?? [])];
      if (type === "Tile") {
        sources.sort((left, right) => numeric(left["sort"]) - numeric(right["sort"]));
      }
      for (const [sourceIndex, source] of sources.entries()) {
        const prepared = prepareOne(
          cloneRecord(source),
          type,
          scene.id,
          delta,
          scene.grid,
          levelMap,
          stack,
          stackStride,
          sourceIndex,
          destination.id,
          onTransform,
        );
        if (!prepared) {
          skipped[type] = (skipped[type] ?? 0) + 1;
          continue;
        }
        const batch = batches.get(type) ?? [];
        batch.push(prepared);
        batches.set(type, batch);
      }
    }
  }
  return { batches, skipped };
}

function prepareOne(
  source: FoundryData,
  type: CoreDocumentType,
  sceneId: string,
  delta: Point,
  grid: SceneGridSettings,
  levelMap: ReadonlyMap<string, string>,
  stack: number,
  stackStride: number,
  sourceIndex: number,
  destinationSceneId: string,
  onTransform?: (data: FoundryData, context: DocumentTransformContext) => void,
): PreparedDocument | undefined {
  const sourceId = documentId(source);
  if (!sourceId) return undefined;
  const identity: SourceDocumentIdentity = { documentId: sourceId, documentType: type, sceneId };
  const context: DocumentTransformContext = {
    delta,
    destinationSceneId,
    documentType: type,
    sourceSceneId: sceneId,
  };
  let data = transformCoreDocument(source, type, delta, grid);
  if (type === "Tile") {
    data["sort"] = (stack + 1) * stackStride + sourceIndex;
  }
  data = attachNestedBehaviorProvenance(data, identity);
  data = applyExtensionTransforms(data, context);
  onTransform?.(data, context);
  data = attachProvenance(data, identity);

  const creationData = transformLevelMembership(
    cloneRecord(data) as LevelMembershipData,
    levelMap,
  ) as FoundryData;
  delete creationData["_id"];
  delete creationData["_stats"];
  stripNestedBehaviorIds(creationData);
  return { creationData, data, identity, type };
}

function transformCoreDocument(
  source: FoundryData,
  type: CoreDocumentType,
  delta: Point,
  grid: SceneGridSettings,
): FoundryData {
  const pointData = { ...source, x: numeric(source["x"]), y: numeric(source["y"]) };
  if (type === "Wall") {
    const coordinates = Array.isArray(source["c"]) ? source["c"] : [0, 0, 0, 0];
    return translateWallDocument(
      {
        ...source,
        c: [
          numeric(coordinates[0]),
          numeric(coordinates[1]),
          numeric(coordinates[2]),
          numeric(coordinates[3]),
        ],
      },
      delta,
    ) as FoundryData;
  }
  if (type === "Drawing") return translateDrawingDocument(pointData as never, delta) as FoundryData;
  if (type === "Region")
    return translateRegionDocument(source as RegionDocumentData, delta, grid) as FoundryData;
  if (type === "Token") return translateTokenDocument(pointData as never, delta) as FoundryData;
  if (type === "Tile") {
    return translateRectangleDocument(
      {
        ...pointData,
        height: numeric(source["height"]),
        width: numeric(source["width"]),
      } as never,
      delta,
    ) as FoundryData;
  }
  return translatePointDocument(pointData as never, delta) as FoundryData;
}

function applyExtensionTransforms(
  data: FoundryData,
  context: DocumentTransformContext,
): FoundryData {
  let transformed = data;
  for (const extension of registeredExtensions()) {
    const transformer = extension.documentTransformers?.[context.documentType];
    if (transformer) transformed = cloneRecord(transformer(transformed, context));
  }
  return transformed;
}

function attachNestedBehaviorProvenance(
  data: FoundryData,
  parent: SourceDocumentIdentity,
): FoundryData {
  if (parent.documentType !== "Region") return data;
  data["behaviors"] = asRecords(data["behaviors"]).map((behavior) => {
    const behaviorId = documentId(behavior);
    return behaviorId
      ? attachProvenance(behavior, {
          documentId: behaviorId,
          documentType: "RegionBehavior",
          parentIds: [parent.documentId],
          sceneId: parent.sceneId,
        })
      : behavior;
  });
  return data;
}

function stripNestedBehaviorIds(data: FoundryData): void {
  const behaviors = asRecords(data["behaviors"]);
  if (behaviors.length === 0) return;
  data["behaviors"] = behaviors.map((behavior) => {
    const clone = cloneRecord(behavior);
    delete clone["_id"];
    delete clone["_stats"];
    return clone;
  });
}
