<script setup lang="ts">
/* eslint-disable vue/html-closing-bracket-newline, vue/html-indent, vue/html-self-closing -- Prettier owns Vue template formatting. */
import { computed } from "vue";

import { estimateMergeCost } from "../../../../functions/scene-merger";
import type { SceneMergerLocalizer } from "../../../../state/scene-merger";
import { useSceneMergerStore } from "../../../../state/scene-merger";
import type { ValidationIssue } from "../../../../types/scene-merger";

defineProps<{ readonly t: SceneMergerLocalizer }>();
const store = useSceneMergerStore();

const estimate = computed(() =>
  estimateMergeCost(store.selectedScenes, store.arrangementBounds, { ...store.content }),
);

function issueKey(issue: ValidationIssue): string {
  return `FVTT_SCENE_MERGER.Validation.Issues.${issue.code.replace(".", "_")}`;
}

function details(issue: ValidationIssue): string {
  return Object.entries(issue.details)
    .map(([key, value]) => `${key}: ${value}`)
    .join(" · ");
}

function formatMillions(value: number): string {
  return value >= 1_000_000 ? `${(value / 1_000_000).toFixed(1)}M` : value.toLocaleString();
}

function acknowledgeWarnings(event: Event): void {
  store.setWarningsAcknowledged((event.currentTarget as HTMLInputElement).checked);
}
</script>

<template>
  <section class="dui-card dui-card-border tw:bg-base-200">
    <div class="dui-card-body tw:gap-3 tw:p-3">
      <div class="tw:flex tw:items-start tw:justify-between tw:gap-2">
        <div>
          <h2 class="dui-card-title tw:text-base">{{ t("FVTT_SCENE_MERGER.Validation.Title") }}</h2>
          <p class="tw:m-0 tw:text-xs tw:opacity-65">
            {{ t("FVTT_SCENE_MERGER.Validation.Help") }}
          </p>
        </div>
        <span v-if="store.validating" class="dui-loading dui-loading-spinner dui-loading-sm" />
        <span
          v-else-if="store.validation?.canMerge"
          class="dui-badge dui-badge-success dui-badge-soft"
          >{{ t("FVTT_SCENE_MERGER.Validation.Ready") }}</span
        >
        <span v-else class="dui-badge dui-badge-error dui-badge-soft">{{
          t("FVTT_SCENE_MERGER.Validation.Blocked")
        }}</span>
      </div>

      <div class="tw:flex tw:flex-wrap tw:gap-1">
        <span class="dui-badge dui-badge-outline dui-badge-sm">{{
          t("FVTT_SCENE_MERGER.Validation.Estimate.Area", {
            value: formatMillions(store.arrangementBounds.width * store.arrangementBounds.height),
          })
        }}</span>
        <span class="dui-badge dui-badge-outline dui-badge-sm">{{
          t("FVTT_SCENE_MERGER.Validation.Estimate.Textures", {
            value: formatMillions(estimate.texturePixels),
          })
        }}</span>
        <span class="dui-badge dui-badge-outline dui-badge-sm">{{
          t("FVTT_SCENE_MERGER.Validation.Estimate.Walls", { value: estimate.documents.Wall ?? 0 })
        }}</span>
        <span class="dui-badge dui-badge-outline dui-badge-sm">{{
          t("FVTT_SCENE_MERGER.Validation.Estimate.Tokens", {
            value: estimate.documents.Token ?? 0,
          })
        }}</span>
        <span
          v-if="estimate.animatedAssets"
          class="dui-badge dui-badge-warning dui-badge-soft dui-badge-sm"
          >{{
            t("FVTT_SCENE_MERGER.Validation.Estimate.Animated", { value: estimate.animatedAssets })
          }}</span
        >
      </div>

      <div v-if="store.validation?.blocking.length" class="tw:grid tw:gap-2">
        <div
          v-for="(issue, index) in store.validation.blocking"
          :key="`${issue.code}-${index}`"
          role="alert"
          class="dui-alert dui-alert-error dui-alert-soft tw:items-start tw:py-2 tw:text-sm"
        >
          <span aria-hidden="true">×</span>
          <span>
            <strong class="tw:block">{{ t(issueKey(issue), issue.details) }}</strong>
            <small v-if="Object.keys(issue.details).length" class="tw:opacity-70">{{
              details(issue)
            }}</small>
          </span>
        </div>
      </div>

      <div v-if="store.validation?.warnings.length" class="tw:grid tw:gap-2">
        <div
          v-for="(issue, index) in store.validation.warnings"
          :key="`${issue.code}-${index}`"
          role="alert"
          class="dui-alert dui-alert-warning dui-alert-soft tw:items-start tw:py-2 tw:text-sm"
        >
          <span aria-hidden="true">!</span>
          <span>
            <strong class="tw:block">{{ t(issueKey(issue), issue.details) }}</strong>
            <small v-if="Object.keys(issue.details).length" class="tw:opacity-70">{{
              details(issue)
            }}</small>
          </span>
        </div>
        <label
          class="tw:flex tw:items-start tw:gap-2 tw:rounded-box tw:bg-warning/10 tw:p-2 tw:text-sm"
        >
          <input
            class="dui-checkbox dui-checkbox-warning dui-checkbox-sm tw:mt-0.5"
            type="checkbox"
            :checked="store.warningsAcknowledged"
            :disabled="!store.setupEditable"
            @change="acknowledgeWarnings"
          />
          <span>
            <strong class="tw:block">{{ t("FVTT_SCENE_MERGER.Validation.Acknowledge") }}</strong>
            <small class="tw:opacity-70">{{
              t("FVTT_SCENE_MERGER.Validation.AcknowledgeHelp")
            }}</small>
          </span>
        </label>
      </div>

      <div
        v-if="
          store.validation && !store.validation.blocking.length && !store.validation.warnings.length
        "
        role="alert"
        class="dui-alert dui-alert-success dui-alert-soft tw:py-2 tw:text-sm"
      >
        <span aria-hidden="true">✓</span>
        <span>{{ t("FVTT_SCENE_MERGER.Validation.NoIssues") }}</span>
      </div>
    </div>
  </section>
</template>
