import type { ContentCategory, ContentSelection, CoreDocumentType } from "../../types/scene-merger";

export const CONTENT_DOCUMENT_TYPES: Readonly<Partial<Record<ContentCategory, CoreDocumentType>>> =
  {
    drawings: "Drawing",
    lights: "AmbientLight",
    notes: "Note",
    regions: "Region",
    sounds: "AmbientSound",
    tiles: "Tile",
    tokens: "Token",
    walls: "Wall",
  };

export function enabledDocumentTypes(selection: ContentSelection): readonly CoreDocumentType[] {
  return Object.entries(CONTENT_DOCUMENT_TYPES).flatMap(([category, documentType]) =>
    selection[category as ContentCategory] && documentType ? [documentType] : [],
  );
}
