import {
  createValidationReport,
  normalizePlacements,
  validateMergeInput,
} from "../../functions/scene-merger";
import type {
  MergeRequest,
  SceneSnapshot,
  ValidationIssue,
  ValidationReport,
} from "../../types/scene-merger";
import { registeredExtensions } from "../extensions/extension-registry";
import { validateSourceAssets } from "./asset-validation";
import { loadSceneSnapshots } from "./scene-snapshots";
import { requireGame } from "./runtime-utils";

export interface RuntimeValidation {
  readonly report: ValidationReport;
  readonly scenes: readonly SceneSnapshot[];
}

export async function validateRequest(request: MergeRequest): Promise<ValidationReport> {
  return (await validateRequestWithScenes(request)).report;
}

export async function validateRequestWithScenes(request: MergeRequest): Promise<RuntimeValidation> {
  const runtime = requireGame();
  const missing = request.sourceSceneIds.filter((id) => !runtime.scenes.get(id));
  const availableIds = request.sourceSceneIds.filter((id) => runtime.scenes.get(id));
  const scenes = loadSceneSnapshots(availableIds);
  const normalizedPlacements = normalizePlacements(request.placements).placements;
  const base = validateMergeInput(scenes, normalizedPlacements, request.options);
  const issues: ValidationIssue[] = [
    ...base.blocking,
    ...base.warnings,
    ...(await validateSourceAssets(scenes, request.options.content)),
    ...missing.map((sceneId) => unavailableIssue(sceneId)),
  ];

  const folderId = request.options.destination.folderId;
  const folder = folderId ? runtime.folders.get(folderId) : undefined;
  if (folderId && (!folder || folder.type !== "Scene")) {
    issues.push({
      code: "destination.folderUnavailable",
      details: { folderId },
      overridable: false,
      sceneIds: [],
      severity: "error",
    });
  }

  if (request.options.content.tokens) {
    for (const scene of scenes) {
      for (const token of scene.documents.Token ?? []) {
        const actorId = token["actorId"];
        if (typeof actorId === "string" && actorId && !runtime.actors.get(actorId)) {
          issues.push({
            code: "tokens.missingActor",
            details: { actorId },
            overridable: true,
            sceneIds: [scene.id],
            severity: "warning",
          });
        }
      }
    }
  }

  if (!runtime.user.isGM || !Scene.implementation.canUserCreate(runtime.user)) {
    issues.push(unavailableIssue("destination"));
  }

  for (const extension of registeredExtensions()) {
    if (extension.validate) {
      issues.push(...extension.validate(scenes, request));
    }
  }

  return { report: createValidationReport(issues), scenes };
}

export function unacknowledgedWarnings(
  request: MergeRequest,
  report: ValidationReport,
): readonly ValidationIssue[] {
  const acknowledged = new Set(request.acknowledgedWarnings);
  return report.warnings.filter(
    (warning) => !acknowledged.has(warning.code) && !acknowledged.has(issueIdentifier(warning)),
  );
}

export function issueIdentifier(issue: ValidationIssue): string {
  return `${issue.code}:${[...issue.sceneIds].sort().join(",")}`;
}

function unavailableIssue(sceneId: string): ValidationIssue {
  return {
    code: "selection.unavailable",
    details: {},
    overridable: false,
    sceneIds: [sceneId],
    severity: "error",
  };
}
