import type { MergeFailureStage } from "../../types/scene-merger";

const MERGE_FAILURE_STAGES = new Set<MergeFailureStage>([
  "beforeDestination",
  "calculatingBounds",
  "copyingDrawings",
  "copyingLights",
  "copyingNotes",
  "copyingRegions",
  "copyingSounds",
  "copyingTiles",
  "copyingTokens",
  "copyingWalls",
  "creatingBackgrounds",
  "creatingScene",
  "finalizing",
  "rewritingReferences",
  "validating",
]);

export function resolveMergeFailureStage(
  error: unknown,
  fallback: MergeFailureStage,
): MergeFailureStage {
  if (typeof error !== "object" || error === null || !("stage" in error)) return fallback;
  const stage = (error as { readonly stage?: unknown }).stage;
  return typeof stage === "string" && MERGE_FAILURE_STAGES.has(stage as MergeFailureStage)
    ? (stage as MergeFailureStage)
    : fallback;
}
