import type { MergeOptions, SnapSettings } from "../../types/scene-merger";

export const DEFAULT_SNAP_SETTINGS: SnapSettings = {
  edgeThreshold: 16,
  gridSize: 100,
  mode: "edge",
  pixelInterval: 50,
};

export function createDefaultMergeOptions(destinationName: string): MergeOptions {
  return {
    content: {
      backgrounds: true,
      drawings: true,
      lights: true,
      notes: true,
      regions: true,
      sounds: true,
      templates: false,
      tiles: true,
      tokens: false,
      walls: true,
    },
    destination: {
      activateAfterMerge: false,
      folderId: null,
      lockBackgroundTiles: true,
      name: destinationName,
      navigation: false,
      openAfterMerge: true,
    },
  };
}
