import type { NormalizedLayout, Point, ScenePlacement } from "../../../types/scene-merger";

import { calculateArrangementBounds, createBounds } from "./bounds";

const ZERO_POINT: Point = { x: 0, y: 0 };

export function normalizePlacements(
  placements: readonly ScenePlacement[],
  destinationOrigin: Point = ZERO_POINT,
): NormalizedLayout {
  const sourceBounds = calculateArrangementBounds(placements);
  const shift = {
    x: destinationOrigin.x - sourceBounds.minX,
    y: destinationOrigin.y - sourceBounds.minY,
  };
  const normalized = placements.map((placement) => ({
    ...placement,
    x: placement.x + shift.x,
    y: placement.y + shift.y,
  }));
  const bounds = createBounds(
    destinationOrigin.x,
    destinationOrigin.y,
    destinationOrigin.x + sourceBounds.width,
    destinationOrigin.y + sourceBounds.height,
  );

  return {
    bounds,
    height: sourceBounds.height,
    placements: normalized,
    shift,
    sourceBounds,
    width: sourceBounds.width,
  };
}
