import type { MergeFailureStage } from "../../../types/scene-merger";
import { errorMessage } from "../runtime-utils";

export class MergeCancelledError extends Error {
  constructor() {
    super("Scene merge cancelled.");
    this.name = "MergeCancelledError";
  }
}

export class SceneMergeError extends Error {
  readonly cleanupError: string | null;
  readonly destinationSceneId: string | null;
  readonly originalError: unknown;
  readonly stage: MergeFailureStage;

  constructor(options: {
    cleanupError?: unknown;
    destinationSceneId?: string;
    error: unknown;
    stage: MergeFailureStage;
  }) {
    const cleanup = options.cleanupError
      ? ` Cleanup also failed: ${errorMessage(options.cleanupError)}`
      : "";
    const partial = options.destinationSceneId
      ? ` Partial destination Scene: ${options.destinationSceneId}.`
      : "";
    super(
      `Scene merge failed during ${options.stage}: ${errorMessage(options.error)}.${cleanup}${partial}`,
    );
    this.name = "SceneMergeError";
    this.cleanupError = options.cleanupError ? errorMessage(options.cleanupError) : null;
    this.destinationSceneId = options.destinationSceneId ?? null;
    this.originalError = options.error;
    this.stage = options.stage;
  }
}

export interface CancellationCheckpoint {
  throwIfCancelled(): void;
}

export class MergeCancellation implements CancellationCheckpoint {
  #cancelled = false;

  cancel(): void {
    this.#cancelled = true;
  }

  throwIfCancelled(): void {
    if (this.#cancelled) throw new MergeCancelledError();
  }
}
