import {
  calculateDocumentDelta,
  CONTENT_DOCUMENT_TYPES,
  isGridTranslationAligned,
} from "../../../functions/scene-merger";
import type {
  CoreDocumentType,
  MergeRequest,
  MergeSummary,
  ScenePlacement,
  SceneSnapshot,
} from "../../../types/scene-merger";
import { asRecords } from "../runtime-utils";
import type { DestinationSceneHandle } from "./foundry-runtime";

export function assertActualGridAlignment(
  scenes: readonly SceneSnapshot[],
  placements: readonly ScenePlacement[],
  destination: DestinationSceneHandle,
): void {
  const placementById = new Map(placements.map((placement) => [placement.sceneId, placement]));
  for (const scene of scenes) {
    if (scene.metrics.gridRegionShapes === 0) continue;
    const placement = placementById.get(scene.id);
    if (!placement) continue;
    const delta = calculateDocumentDelta(scene.dimensions, destination.dimensions, placement);
    if (!isGridTranslationAligned(delta, scene.grid.size)) {
      throw new Error(
        `Scene ${scene.name} has grid Region geometry which is not aligned after destination insets.`,
      );
    }
  }
}

export function countSkippedDocuments(
  scenes: readonly SceneSnapshot[],
  request: MergeRequest,
  skippedDuringPreparation: Readonly<Partial<Record<CoreDocumentType, number>>>,
): Partial<Record<CoreDocumentType, number>> {
  const skipped = { ...skippedDuringPreparation };
  for (const [category, type] of Object.entries(CONTENT_DOCUMENT_TYPES)) {
    if (!type || request.options.content[category as keyof typeof request.options.content])
      continue;
    skipped[type] = scenes.reduce(
      (total, scene) => total + (scene.documents[type]?.length ?? 0),
      skipped[type] ?? 0,
    );
  }
  return skipped;
}

export function countRegionBehaviors(
  regions: readonly Readonly<Record<string, unknown>>[],
): number {
  return regions.reduce((total, region) => total + asRecords(region["behaviors"]).length, 0);
}

export function createSummary(
  scenes: readonly SceneSnapshot[],
  destination: DestinationSceneHandle,
  copied: Readonly<Partial<Record<CoreDocumentType, number>>>,
  skipped: Readonly<Partial<Record<CoreDocumentType, number>>>,
  referencesRewritten: number,
  unresolvedReferences: readonly string[],
  validationWarnings: readonly string[],
): MergeSummary {
  const unresolved = [...new Set(unresolvedReferences)];
  const warnings = [...validationWarnings];
  if (unresolved.length > 0) {
    warnings.push(`${unresolved.length} reference or provenance entries require manual review.`);
  }
  return {
    copied,
    destinationHeight: destination.dimensions.sceneHeight,
    destinationSceneId: destination.id,
    destinationSceneName: destination.name,
    destinationWidth: destination.dimensions.sceneWidth,
    referencesRewritten,
    skipped,
    sourceCount: scenes.length,
    unresolvedReferences: unresolved,
    warnings,
  };
}
