import type {
  MergeOptions,
  ScenePlacement,
  SceneSummary,
  ValidationIssue,
} from "../../../types/scene-merger";

import { findPlacementOverlaps } from "../layout/overlaps";

function issue(
  code: ValidationIssue["code"],
  severity: ValidationIssue["severity"],
  sceneIds: readonly string[],
  details: ValidationIssue["details"] = {},
  overridable = severity !== "error",
): ValidationIssue {
  return { code, details, overridable, sceneIds, severity };
}

function duplicateIds(values: readonly string[]): readonly string[] {
  const seen = new Set<string>();
  const duplicates = new Set<string>();

  for (const value of values) {
    if (seen.has(value)) {
      duplicates.add(value);
    }
    seen.add(value);
  }

  return [...duplicates];
}

function invalidPlacement(placement: ScenePlacement): boolean {
  return (
    !Number.isFinite(placement.x) ||
    !Number.isFinite(placement.y) ||
    !Number.isFinite(placement.width) ||
    !Number.isFinite(placement.height) ||
    !Number.isFinite(placement.x + placement.width) ||
    !Number.isFinite(placement.y + placement.height) ||
    placement.width <= 0 ||
    placement.height <= 0
  );
}

function compareGridSettings(scenes: readonly SceneSummary[]): readonly ValidationIssue[] {
  const baseline = scenes[0];

  if (!baseline) {
    return [];
  }

  const issues: ValidationIssue[] = [];

  for (const scene of scenes.slice(1)) {
    const sceneIds = [baseline.id, scene.id];

    if (scene.grid.type !== baseline.grid.type) {
      issues.push(issue("grid.typeMismatch", "error", sceneIds));
    }
    if (scene.grid.size !== baseline.grid.size) {
      issues.push(issue("grid.sizeMismatch", "error", sceneIds));
    }
    if (scene.grid.distance !== baseline.grid.distance) {
      issues.push(issue("grid.distanceMismatch", "error", sceneIds));
    }
    if (scene.grid.units !== baseline.grid.units) {
      issues.push(issue("grid.unitsMismatch", "error", sceneIds));
    }
  }

  return issues;
}

function sceneWarnings(
  scene: SceneSummary,
  placement: ScenePlacement | undefined,
  options: MergeOptions,
): readonly ValidationIssue[] {
  const issues: ValidationIssue[] = [];
  const background = scene.background;

  if (
    options.content.backgrounds &&
    background &&
    (background.x !== 0 ||
      background.y !== 0 ||
      background.rotation !== 0 ||
      background.scaleX !== 1 ||
      background.scaleY !== 1)
  ) {
    issues.push(issue("background.transform", "warning", [scene.id]));
  }

  if (scene.metrics.crossSceneReferences > 0) {
    issues.push(
      issue("references.crossScene", "warning", [scene.id], {
        count: scene.metrics.crossSceneReferences,
      }),
    );
  }
  if (scene.metrics.moduleFlagDocuments > 0) {
    issues.push(
      issue("flags.moduleData", "warning", [scene.id], {
        count: scene.metrics.moduleFlagDocuments,
      }),
    );
  }
  if (options.content.regions && scene.metrics.unsupportedRegionBehaviors > 0) {
    issues.push(
      issue("regions.unsupportedBehavior", "warning", [scene.id], {
        count: scene.metrics.unsupportedRegionBehaviors,
      }),
    );
  }
  if (options.content.regions && scene.metrics.attachedRegions > 0) {
    issues.push(
      issue("regions.attachedUnsupported", "error", [scene.id], {
        count: scene.metrics.attachedRegions,
      }),
    );
  }
  if (options.content.regions && scene.metrics.unsupportedRegionShapes > 0) {
    issues.push(
      issue("regions.unsupportedShape", "error", [scene.id], {
        count: scene.metrics.unsupportedRegionShapes,
      }),
    );
  }
  if (options.content.regions && scene.metrics.tokenRegionShapes > 0) {
    issues.push(
      issue("regions.tokenShapeUnsupported", "error", [scene.id], {
        count: scene.metrics.tokenRegionShapes,
      }),
    );
  }
  if (options.content.regions && scene.metrics.gridRegionShapes > 0 && scene.grid.type !== 1) {
    issues.push(issue("grid.regionShapeUnsupported", "error", [scene.id]));
  }
  if (
    options.content.regions &&
    placement &&
    scene.metrics.gridRegionShapes > 0 &&
    scene.grid.type === 1 &&
    scene.grid.size > 0 &&
    (placement.x % scene.grid.size !== 0 || placement.y % scene.grid.size !== 0)
  ) {
    issues.push(issue("grid.regionAlignment", "error", [scene.id]));
  }

  return issues;
}

export function validateCompatibility(
  scenes: readonly SceneSummary[],
  placements: readonly ScenePlacement[],
  options: MergeOptions,
): readonly ValidationIssue[] {
  const issues: ValidationIssue[] = [];
  const placementByScene = new Map(placements.map((placement) => [placement.sceneId, placement]));

  if (!options.destination.name.trim()) {
    issues.push(issue("destination.nameRequired", "error", []));
  }

  if (scenes.length < 2) {
    issues.push(
      issue(
        "selection.tooFew",
        "error",
        scenes.map((scene) => scene.id),
      ),
    );
  }

  const repeatedScenes = duplicateIds(scenes.map((scene) => scene.id));
  if (repeatedScenes.length > 0) {
    issues.push(issue("selection.duplicate", "error", repeatedScenes));
  }

  const repeatedPlacements = duplicateIds(placements.map((placement) => placement.sceneId));
  if (repeatedPlacements.length > 0) {
    issues.push(issue("layout.duplicate", "error", repeatedPlacements));
  }

  const sourceIds = new Set(scenes.map((scene) => scene.id));
  const unknownPlacements = [
    ...new Set(
      placements.map((placement) => placement.sceneId).filter((sceneId) => !sourceIds.has(sceneId)),
    ),
  ];
  if (unknownPlacements.length > 0) {
    issues.push(issue("layout.unknown", "error", unknownPlacements));
  }

  for (const scene of scenes) {
    const placement = placementByScene.get(scene.id);

    if (!scene.canMerge) {
      issues.push(issue("selection.unavailable", "error", [scene.id]));
    }
    if (!placement) {
      issues.push(issue("layout.missing", "error", [scene.id]));
    } else if (
      invalidPlacement(placement) ||
      placement.width !== scene.dimensions.sceneWidth ||
      placement.height !== scene.dimensions.sceneHeight
    ) {
      issues.push(
        issue("layout.invalidDimensions", "error", [scene.id], {
          actualHeight: placement.height,
          actualWidth: placement.width,
          expectedHeight: scene.dimensions.sceneHeight,
          expectedWidth: scene.dimensions.sceneWidth,
        }),
      );
    }
    if (scene.levels.length !== 1) {
      issues.push(issue("levels.multiple", "error", [scene.id], { count: scene.levels.length }));
    }

    issues.push(...sceneWarnings(scene, placement, options));
  }

  issues.push(...compareGridSettings(scenes));

  if (options.content.backgrounds) {
    const colors = new Set(scenes.map((scene) => String(scene.background?.color ?? "none")));
    if (colors.size > 1) {
      issues.push(
        issue(
          "background.colorMismatch",
          "warning",
          scenes.map((scene) => scene.id),
        ),
      );
    }
  }

  for (const overlap of findPlacementOverlaps(placements)) {
    issues.push(
      issue("layout.overlap", "warning", [overlap.firstSceneId, overlap.secondSceneId], {
        height: overlap.intersection.height,
        width: overlap.intersection.width,
      }),
    );
  }

  if (options.content.templates) {
    issues.push(issue("content.templatesUnavailable", "error", []));
  }

  return issues;
}
