import type {
  CoreDocumentType,
  ReferenceRewriteContext,
  ReferenceRewriteResult,
  SerializedRecord,
} from "../../../types/scene-merger";

import { cloneData } from "../transforms/clone";
import { mappedDocumentId, rewriteSceneUuid } from "./uuid";

interface RewriteAccumulator {
  rewritten: number;
  unresolved: string[];
}

function rewriteLevelMembership(
  data: Record<string, unknown>,
  context: ReferenceRewriteContext,
  accumulator: RewriteAccumulator,
): void {
  if (typeof data["level"] === "string") {
    const sourceId = data["level"];
    const mappedId = mappedDocumentId(context, "Level", sourceId);

    if (mappedId) {
      data["level"] = mappedId;
      accumulator.rewritten += 1;
    } else {
      accumulator.unresolved.push(`Level.${sourceId}`);
    }
  }

  if (Array.isArray(data["levels"])) {
    data["levels"] = data["levels"].map((sourceId: unknown) => {
      if (typeof sourceId !== "string") {
        return sourceId;
      }

      const mappedId = mappedDocumentId(context, "Level", sourceId);

      if (mappedId) {
        accumulator.rewritten += 1;
        return mappedId;
      }

      accumulator.unresolved.push(`Level.${sourceId}`);
      return sourceId;
    });
  }
}

function rewriteUuidValue(
  value: unknown,
  context: ReferenceRewriteContext,
  accumulator: RewriteAccumulator,
): unknown {
  if (typeof value !== "string") {
    return value;
  }

  const result = rewriteSceneUuid(value, context);
  accumulator.rewritten += result.rewritten;
  accumulator.unresolved.push(...result.unresolved);
  return result.value;
}

function rewriteTokenId(
  record: Record<string, unknown>,
  key: string,
  context: ReferenceRewriteContext,
  accumulator: RewriteAccumulator,
): void {
  const sourceId = record[key];

  if (typeof sourceId !== "string") {
    return;
  }

  const mappedId = mappedDocumentId(context, "Token", sourceId);

  if (mappedId) {
    record[key] = mappedId;
    accumulator.rewritten += 1;
  } else {
    accumulator.unresolved.push(`Token.${sourceId}`);
  }
}

function rewriteDestination(
  destination: unknown,
  context: ReferenceRewriteContext,
  accumulator: RewriteAccumulator,
): unknown {
  if (typeof destination === "string") {
    return rewriteUuidValue(destination, context, accumulator);
  }

  if (!destination || typeof destination !== "object" || Array.isArray(destination)) {
    return destination;
  }

  const result = cloneData(destination) as Record<string, unknown>;

  if (typeof result["uuid"] === "string") {
    result["uuid"] = rewriteUuidValue(result["uuid"], context, accumulator);
  }

  const targetSceneId = result["scene"];
  if (
    typeof targetSceneId === "string" &&
    context.sourceSceneIds.includes(targetSceneId) &&
    typeof result["region"] === "string"
  ) {
    const mappedId = mappedDocumentId(context, "Region", result["region"], [], targetSceneId);

    if (mappedId) {
      result["scene"] = context.destinationSceneId;
      result["region"] = mappedId;
      accumulator.rewritten += 2;
    } else {
      accumulator.unresolved.push(`Region.${String(result["region"])}`);
    }
  }

  return result;
}

function rewriteBehavior(
  behavior: unknown,
  regionId: string | undefined,
  context: ReferenceRewriteContext,
  accumulator: RewriteAccumulator,
): unknown {
  if (!behavior || typeof behavior !== "object" || Array.isArray(behavior)) {
    return behavior;
  }

  const result = cloneData(behavior) as Record<string, unknown>;
  const system = result["system"];

  if (!system || typeof system !== "object" || Array.isArray(system)) {
    return result;
  }

  const rewrittenSystem = { ...(system as Record<string, unknown>) };
  const type = typeof result["type"] === "string" ? result["type"].toLowerCase() : "";

  if (type.includes("teleport") && Array.isArray(rewrittenSystem["destinations"])) {
    rewrittenSystem["destinations"] = rewrittenSystem["destinations"].map((destination) =>
      rewriteDestination(destination, context, accumulator),
    );
  }

  if (type.includes("toggle") && regionId) {
    for (const key of ["enable", "disable"]) {
      if (!Array.isArray(rewrittenSystem[key])) {
        continue;
      }

      rewrittenSystem[key] = rewrittenSystem[key].map((sourceId: unknown) => {
        if (typeof sourceId !== "string") {
          return sourceId;
        }

        if (sourceId.startsWith("Scene.")) {
          return rewriteUuidValue(sourceId, context, accumulator);
        }

        const mappedId = mappedDocumentId(context, "RegionBehavior", sourceId, [regionId]);

        if (mappedId) {
          accumulator.rewritten += 1;
          return mappedId;
        }

        accumulator.unresolved.push(`Region.${regionId}.RegionBehavior.${sourceId}`);
        return sourceId;
      });
    }
  }

  result["system"] = rewrittenSystem;
  return result;
}

function rewriteRegionReferences(
  data: Record<string, unknown>,
  context: ReferenceRewriteContext,
  accumulator: RewriteAccumulator,
): void {
  const attachment = data["attachment"];

  if (attachment && typeof attachment === "object" && !Array.isArray(attachment)) {
    const rewrittenAttachment = cloneData(attachment) as Record<string, unknown>;
    rewriteTokenId(rewrittenAttachment, "token", context, accumulator);
    data["attachment"] = rewrittenAttachment;
  }

  if (Array.isArray(data["shapes"])) {
    data["shapes"] = data["shapes"].map((shape: unknown) => {
      if (!shape || typeof shape !== "object" || Array.isArray(shape)) {
        return shape;
      }

      const rewrittenShape = cloneData(shape) as Record<string, unknown>;
      rewriteTokenId(rewrittenShape, "token", context, accumulator);
      return rewrittenShape;
    });
  }

  const regionId = typeof data["_id"] === "string" ? data["_id"] : undefined;

  if (Array.isArray(data["behaviors"])) {
    data["behaviors"] = data["behaviors"].map((behavior) =>
      rewriteBehavior(behavior, regionId, context, accumulator),
    );
  }
}

export function rewriteKnownReferences<T extends SerializedRecord>(
  documentType: CoreDocumentType,
  data: T,
  context: ReferenceRewriteContext,
): ReferenceRewriteResult<T> {
  const value = cloneData(data) as Record<string, unknown>;
  const accumulator: RewriteAccumulator = { rewritten: 0, unresolved: [] };

  rewriteLevelMembership(value, context, accumulator);

  if (documentType === "Region") {
    rewriteRegionReferences(value, context, accumulator);
  }

  return {
    rewritten: accumulator.rewritten,
    unresolved: accumulator.unresolved,
    value: value as T,
  };
}
