import { createSourceDocumentKey, rewriteKnownReferences } from "../../functions/scene-merger";
import type { FoundryData } from "../../types/foundry";
import type {
  CoreDocumentType,
  ReferenceRewriteContext,
  SourceDocumentKey,
} from "../../types/scene-merger";
import { registeredExtensions } from "../extensions/extension-registry";
import type { PreparedDocument } from "./prepare-documents";
import { removeTemporaryProvenance } from "./provenance";
import { asRecord, asRecords, cloneRecord, documentId } from "./runtime-utils";

export interface ReferenceUpdates {
  readonly referencesRewritten: number;
  readonly unresolved: readonly string[];
  readonly updates: ReadonlyMap<CoreDocumentType, readonly FoundryData[]>;
}

export function prepareReferenceUpdates(
  batches: ReadonlyMap<CoreDocumentType, readonly PreparedDocument[]>,
  idMap: ReadonlyMap<SourceDocumentKey, string>,
  destinationSceneId: string,
  sourceSceneIds: readonly string[],
  onRewrite?: (data: FoundryData, context: ReferenceRewriteContext) => void,
): ReferenceUpdates {
  const updates = new Map<CoreDocumentType, FoundryData[]>();
  const unresolved: string[] = [];
  let referencesRewritten = 0;

  for (const [type, batch] of batches) {
    for (const prepared of batch) {
      const context: ReferenceRewriteContext = {
        destinationSceneId,
        idMap,
        sourceSceneId: prepared.identity.sceneId,
        sourceSceneIds,
      };
      const destinationId = idMap.get(
        createSourceDocumentKey(prepared.identity.sceneId, type, prepared.identity.documentId),
      );
      if (!destinationId) {
        unresolved.push(`${type}.${prepared.identity.documentId}`);
        continue;
      }

      const result = rewriteKnownReferences(type, prepared.data, context);
      let value = cloneRecord(result.value);
      referencesRewritten += result.rewritten;
      unresolved.push(...result.unresolved);
      for (const extension of registeredExtensions()) {
        if (!extension.referenceRewriter) continue;
        const extensionResult = extension.referenceRewriter(value, context);
        value = cloneRecord(extensionResult.value);
        referencesRewritten += extensionResult.rewritten;
        unresolved.push(...extensionResult.unresolved);
      }
      onRewrite?.(value, context);
      value["_id"] = destinationId;
      if (type === "Region")
        remapRegionBehaviorIds(value, prepared.identity.documentId, context, unresolved);
      unresolved.push(...detectUnknownFlagReferences(value, sourceSceneIds, type));
      value = removeTemporaryProvenance(value);
      const typeUpdates = updates.get(type) ?? [];
      typeUpdates.push(value);
      updates.set(type, typeUpdates);
    }
  }
  return {
    referencesRewritten,
    unresolved: [...new Set(unresolved)],
    updates,
  };
}

function remapRegionBehaviorIds(
  region: FoundryData,
  sourceRegionId: string,
  context: ReferenceRewriteContext,
  unresolved: string[],
): void {
  region["behaviors"] = asRecords(region["behaviors"]).map((behavior) => {
    const sourceId = documentId(behavior);
    if (!sourceId) return behavior;
    const destinationId = context.idMap.get(
      createSourceDocumentKey(context.sourceSceneId, "RegionBehavior", sourceId, [sourceRegionId]),
    );
    if (!destinationId) {
      unresolved.push(`Region.${sourceRegionId}.RegionBehavior.${sourceId}`);
      return behavior;
    }
    return { ...behavior, _id: destinationId };
  });
}

function detectUnknownFlagReferences(
  document: FoundryData,
  sourceSceneIds: readonly string[],
  type: CoreDocumentType,
): readonly string[] {
  const flags = asRecord(document["flags"]);
  if (!flags) return [];
  const found: string[] = [];
  scanReferenceStrings(flags, "flags", sourceSceneIds, (path) => {
    found.push(`${type}.${documentId(document) ?? "unknown"}:${path}`);
  });
  return found;
}

function scanReferenceStrings(
  value: unknown,
  path: string,
  sourceSceneIds: readonly string[],
  found: (path: string) => void,
): void {
  if (typeof value === "string") {
    if (sourceSceneIds.some((sceneId) => value.includes(`Scene.${sceneId}.`))) found(path);
    return;
  }
  if (Array.isArray(value)) {
    value.forEach((child, index) =>
      scanReferenceStrings(child, `${path}[${index}]`, sourceSceneIds, found),
    );
    return;
  }
  const record = asRecord(value);
  if (!record) return;
  for (const [key, child] of Object.entries(record)) {
    scanReferenceStrings(child, `${path}.${key}`, sourceSceneIds, found);
  }
}
