import type {
  DrawingDocumentData,
  LevelMembershipData,
  Point,
  PointDocumentData,
  RectangleDocumentData,
  WallDocumentData,
} from "../../../types/scene-merger";

import { cloneData } from "./clone";
import { translatePoint } from "./coordinates";

export function translatePointDocument<T extends PointDocumentData>(data: T, delta: Point): T {
  const clone = cloneData(data);
  return { ...clone, ...translatePoint(data, delta) };
}

export function translateRectangleDocument<T extends RectangleDocumentData>(
  data: T,
  delta: Point,
): T {
  return translatePointDocument(data, delta);
}

export function translateWallDocument<T extends WallDocumentData>(data: T, delta: Point): T {
  const clone = cloneData(data);

  return {
    ...clone,
    c: [data.c[0] + delta.x, data.c[1] + delta.y, data.c[2] + delta.x, data.c[3] + delta.y],
  };
}

export function translateDrawingDocument<T extends DrawingDocumentData>(data: T, delta: Point): T {
  return translatePointDocument(data, delta);
}

export function translateTokenDocument<T extends PointDocumentData>(data: T, delta: Point): T {
  const translated = translatePointDocument(data, delta);

  return {
    ...translated,
    _movementHistory: [],
    _regions: [],
  };
}

export function transformLevelMembership<T extends LevelMembershipData>(
  data: T,
  levelIdMap: ReadonlyMap<string, string>,
): T {
  const clone = cloneData(data);
  const result: Record<string, unknown> = { ...clone };

  if (typeof data.level === "string") {
    result["level"] = levelIdMap.get(data.level) ?? data.level;
  }

  if (Array.isArray(data.levels)) {
    result["levels"] = data.levels.map((levelId) => levelIdMap.get(levelId) ?? levelId);
  }

  return result as T;
}
